import Konva from 'https://cdn.jsdelivr.net/npm/konva@10/+esm';
const el = document.getElementById('stage');
const stage = Konva.Node.create(data.scene, el); // data.scene:序列化场景树,root className 'Stage' 且 attrs.width/height 必填
const layer = stage.getLayers()[0];
if (data.transform && layer) { const tr = new Konva.Transformer(); layer.add(tr); tr.nodes(layer.find('.editable')); layer.draw(); }

